css:
.screen{ --brand: #635bff; --brand2: #00d4ff; --ink: #0a2540; --muted: #425466; --line: #e6ebf1; --radius: 14px; }
*{ box-sizing: border-box; margin: 0px; padding: 0px; }
.screen, .screen{ scroll-behavior: smooth; }
.screen{ font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif; color: var(--ink); background: linear-gradient(rgb(246, 249, 252) 0%, rgb(255, 255, 255) 28%); line-height: 1.5; -webkit-font-smoothing: antialiased; }
.wrap{ max-width: 1080px; margin: 0px auto; padding: 0px 24px; }
header{ position: sticky; top: 0px; z-index: 20; background: rgba(255, 255, 255, 0.82); backdrop-filter: blur(10px); border-bottom: 1px solid var(--line); }
.hrow{ display: flex; align-items: center; justify-content: space-between; padding: 18px 0px; }
.logo{ display: flex; align-items: center; gap: 10px; font-weight: 800; font-size: 21px; }
.logo .dot{ width: 26px; height: 26px; border-radius: 8px; background: linear-gradient(135deg,var(--brand),var(--brand2)); box-shadow: rgba(99, 91, 255, 0.6) 0px 6px 16px -4px; }
nav a{ margin-left: 26px; color: var(--muted); text-decoration: none; font-weight: 600; font-size: 14px; transition: color 0.2s; }
nav a:hover{ color: var(--ink); }
.hero{ padding: 100px 0px 76px; text-align: center; }
.eyebrow{ display: inline-block; padding: 6px 14px; border-radius: 999px; background: rgb(240, 244, 255); color: var(--brand); font-size: 13px; font-weight: 700; margin-bottom: 22px; }
.hero h1{ font-size: 66px; font-weight: 800; letter-spacing: -2.5px; line-height: 1.04; background: linear-gradient(120deg, rgb(10, 37, 64) 20%, rgb(99, 91, 255)) text; -webkit-text-fill-color: transparent; }
.hero p{ font-size: 21px; color: var(--muted); margin: 22px auto 0px; max-width: 600px; }
.cta{ display: inline-flex; gap: 12px; margin-top: 34px; }
.btn{ padding: 14px 28px; border-radius: 999px; font-weight: 700; font-size: 15px; border: 0px; cursor: pointer; transition: transform 0.15s, box-shadow 0.15s; }
.btn.primary{ background: var(--brand); color: rgb(255, 255, 255); box-shadow: rgba(99, 91, 255, 0.65) 0px 10px 28px -8px; }
.btn.primary:hover{ transform: translateY(-2px); }
.btn.ghost{ background: rgb(255, 255, 255); color: var(--ink); box-shadow: rgba(10, 37, 64, 0.1) 0px 2px 10px; }
.logos{ display: flex; justify-content: center; gap: 44px; padding: 36px 0px; opacity: 0.6; font-weight: 800; letter-spacing: 1px; color: var(--muted); }
.grid{ display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; padding: 60px 0px; }
.card{ position: relative; background: rgb(255, 255, 255); border: 1px solid var(--line); border-radius: var(--radius); padding: 28px; box-shadow: rgba(10, 37, 64, 0.22) 0px 24px 50px -28px; transition: transform 0.2s, box-shadow 0.2s; }
.card:hover{ transform: translateY(-4px); box-shadow: rgba(10, 37, 64, 0.3) 0px 32px 60px -24px; }
.card::before{ content: ""; position: absolute; inset: 0px 0px auto; height: 3px; border-radius: 14px 14px 0px 0px; background: linear-gradient(90deg,var(--brand),var(--brand2)); }
.card .ic{ width: 42px; height: 42px; border-radius: 11px; background: rgb(240, 244, 255); display: flex; align-items: center; justify-content: center; margin-bottom: 16px; }
.card h3{ font-size: 19px; margin-bottom: 9px; }
.card p{ color: var(--muted); font-size: 15px; }
.stats{ display: flex; justify-content: space-around; gap: 24px; padding: 56px 0px; margin: 40px 0px; border-top: 1px solid var(--line); border-bottom: 1px solid var(--line); }
.stat{ text-align: center; }
.stat .n{ font-size: 46px; font-weight: 800; background-image: ; background-position-x: ; background-position-y: ; background-size: ; background-repeat: ; background-attachment: ; background-origin: ; background-color: ; background-clip: text; -webkit-text-fill-color: transparent; }
.stat .l{ color: var(--muted); font-size: 14px; margin-top: 6px; }
.signup{ max-width: 460px; margin: 64px auto; padding: 32px; border: 1px solid var(--line); border-radius: var(--radius); box-shadow: rgba(10, 37, 64, 0.2) 0px 24px 50px -28px; background: rgb(255, 255, 255); }
.signup h3{ font-size: 22px; margin-bottom: 16px; text-align: center; }
.field{ display: flex; flex-direction: column; gap: 6px; margin-bottom: 14px; }
.field label{ font-size: 13px; font-weight: 600; color: var(--muted); }
.field input{ padding: 12px 14px; border: 1px solid var(--line); border-radius: 9px; font-size: 15px; }
.anim{ width: 60px; height: 60px; margin: 30px auto; border-radius: 50%; background: conic-gradient(var(--brand),var(--brand2),var(--brand)); animation: 2s linear 0s infinite normal none running spin; }
footer{ padding: 48px 0px; border-top: 1px solid var(--line); color: var(--muted); font-size: 14px; text-align: center; }
*,*::before,*::after{animation:none!important;transition:none!important}
.screen{background:rgba(0, 0, 0, 0);background-image:linear-gradient(rgb(246, 249, 252) 0%, rgb(255, 255, 255) 28%);color:rgb(10, 37, 64);font-family:-apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;font-size:16px;line-height:1.5000;overflow:visible;height:auto;min-height:0}
